int[] scores = {85, 62, 91, 70, 77};
int passCount = 0;
for (int i = 0; i < scores.length; i++) {
    if (scores[i] > 70) {
        System.out.println("Passing score: " + scores[i]);
        passCount++;
    }
}
System.out.println("Students who passed: " + passCount);

